[CmdletBinding(SupportsShouldProcess=$true)]
param([switch]$RestartServices,[switch]$ClearCache,[switch]$RepairWebView2,[switch]$ResetPackage,[switch]$Force,[string]$OutputPath="$env:USERPROFILE\Desktop\PowerAutomateRepair")
$ErrorActionPreference='Stop';New-Item -ItemType Directory -Path $OutputPath -Force|Out-Null;$Log=Join-Path $OutputPath ("repair-{0:yyyyMMdd-HHmmss}.log"-f(Get-Date));function L($m){"$(Get-Date -Format s) $m"|Tee-Object -FilePath $Log -Append};if(-not($RestartServices-or$ClearCache-or$RepairWebView2-or$ResetPackage)){throw'Choose at least one repair action.'}
Get-Process PAD.Console,Microsoft.Flow.RPA.Desktop -ErrorAction SilentlyContinue|Select Name,Id,Path|Export-Csv (Join-Path $OutputPath 'processes-before.csv') -NoTypeInformation
if($RestartServices){foreach($s in'UIFlowService','PowerAutomateService'){if(Get-Service $s -ErrorAction SilentlyContinue){if($PSCmdlet.ShouldProcess($s,'Restart service')){Restart-Service $s -Force;L"Restarted $s"}}}}
if($ClearCache){$p=Get-Process PAD.Console,Microsoft.Flow.RPA.Desktop -ErrorAction SilentlyContinue;if($p-and-not$Force){throw'Close Power Automate Desktop or use -Force.'};if($p){$p|Stop-Process -Force};foreach($x in @("$env:LOCALAPPDATA\Microsoft\Power Automate Desktop\Cache","$env:LOCALAPPDATA\Microsoft\Power Automate Desktop\WebView2")){if(Test-Path $x){if($PSCmdlet.ShouldProcess($x,'Clear application cache')){Get-ChildItem $x -Force -ErrorAction SilentlyContinue|Remove-Item -Recurse -Force -ErrorAction SilentlyContinue}}};L'Power Automate cache cleared.'}
if($RepairWebView2){$setup=Get-ChildItem "$env:ProgramFiles(x86)\Microsoft\EdgeWebView\Application" -Filter setup.exe -Recurse -ErrorAction SilentlyContinue|Select-Object -First 1 -Expand FullName;if(-not$setup){throw'WebView2 setup not found.'};if($PSCmdlet.ShouldProcess('WebView2 Runtime','Repair')){Start-Process $setup '--repair --msedgewebview --system-level' -Wait;L'WebView2 repaired.'}}
if($ResetPackage){$pkg=Get-AppxPackage *PowerAutomateDesktop* -ErrorAction SilentlyContinue|Select-Object -First 1;if(-not$pkg){throw'Power Automate Desktop package not found.'};if($PSCmdlet.ShouldProcess($pkg.PackageFullName,'Reset app package')){Reset-AppxPackage -Package $pkg.PackageFullName;L'Application package reset.'}}
L'Repair workflow finished.'